from typing import Any, Literal, TypeVar

from pydantic import Field

from semantic_kernel.contents.const import REASONING_CONTENT_TAG, ContentTypes
from semantic_kernel.contents.kernel_content import KernelContent

_T = TypeVar("_T", bound="ReasoningContent")


class ReasoningContent(KernelContent):
    """Represents reasoning content generated by an AI model during the response process.

    This content type contains the reasoning steps and summary that the model used
    when generating a response, particularly useful for O-series models that provide
    detailed reasoning capabilities.
    """

    content_type: Literal[ContentTypes.REASONING_CONTENT] = Field(default=REASONING_CONTENT_TAG, init=False)  # type: ignore
    reasoning_id: str = Field(..., description="The unique identifier of the reasoning content.")
    summary_text: str = Field(default="", description="A short summary of the reasoning used by the model.")
    encrypted_content: str | None = Field(default=None, description="The encrypted reasoning content, if available.")
    status: str | None = Field(default=None, description="The status of the reasoning item.")

    def __str__(self) -> str:
        """Return the summary text as the string representation."""
        return self.summary_text

    def to_element(self) -> dict[str, Any]:
        """Convert the reasoning content to an element dictionary."""
        return {
            "type": "reasoning",
            "id": self.reasoning_id,
            "summary_text": self.summary_text,
            "encrypted_content": self.encrypted_content,
            "status": self.status,
        }

    @classmethod
    def from_element(cls: type[_T], element: dict[str, Any]) -> _T:
        """Create a ReasoningContent from an element dictionary.

        Args:
            element: The element dictionary

        Returns:
            A ReasoningContent object
        """
        return cls(
            reasoning_id=element.get("id", ""),
            summary_text=element.get("summary_text", ""),
            encrypted_content=element.get("encrypted_content"),
            status=element.get("status"),
        )

    def to_dict(self) -> dict[str, Any]:
        """Convert the reasoning content to a dictionary."""
        return {
            "type": "reasoning",
            "id": self.reasoning_id,
            "summary_text": self.summary_text,
            "encrypted_content": self.encrypted_content,
            "status": self.status,
        }

    @classmethod
    def from_response_reasoning_item(cls, reasoning_item: Any) -> "ReasoningContent":
        """Create a ReasoningContent from an OpenAI ResponseReasoningItem.

        Args:
            reasoning_item: The OpenAI ResponseReasoningItem object

        Returns:
            A ReasoningContent object
        """
        # Extract summary text from the summary list
        summary_text = ""
        if hasattr(reasoning_item, "summary") and reasoning_item.summary:
            summary_texts = [s.text for s in reasoning_item.summary if hasattr(s, "text")]
            summary_text = " ".join(summary_texts)

        return cls(
            reasoning_id=reasoning_item.id,
            summary_text=summary_text,
            encrypted_content=getattr(reasoning_item, "encrypted_content", None),
            status=getattr(reasoning_item, "status", None),
        )
